      cmTray = s.cm.items.filter(i=>!i.placed).map(i=>({ id:i.id, color:i.color, glow:i.glow, selected:s.cm.selected===i.id, scale:s.cm.selected===i.id?'1.18':'1', ring:s.cm.selected===i.id?'3px solid #FFF3C4':'none', onTap:()=>this.selectItem(i.id) }));
