        const cell=f.cells[r][c];
        if(!cell || cell.type==='empty'){ flowCells.push({ key:r+'-'+c, hub:'transparent', cellBg:'rgba(255,255,255,.04)', cellShadow:'none', segs:[], onTap:()=>{} }); continue; }
        const fill=!!filled[r+','+c]; const col= fill ? '#54C7E0' : '#8ea6b6';
