      shapeTray=s.shp.tray.filter(p=>!p.used).map(p=>({ id:p.id, cp:p.cp, br:p.br, sel:s.shp.selected===p.id, scale:s.shp.selected===p.id?'1.16':'1', onTap:()=>this.shapeSelect(p.id) }));
