      wordEmoji=W.emoji;
      wordSlots=W.word.split('').map((ch,i)=>{ const filled=i<W.built.length;
        return { ch: filled?ch:'', bg: filled?'linear-gradient(180deg,#3DBE9B,#2a9a7c)':'rgba(255,255,255,.08)', border: filled?'rgba(255,255,255,.5)':'rgba(255,255,255,.3)' }; });
      wordTiles=W.letters.map(t=>({ ch:t.ch, op: W.usedIds.includes(t.id)?'.22':'1', onTap:()=>this.wordTap(t.id) }));
